&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%9E%8E%E7%9C%BC%E5%8E%A8%E5%B8%88%E5%85%B3&#34;&gt;瞎眼厨师关&lt;/a&gt;&lt;/li&gt;
