&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;走&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;walk&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;伽马值&lt;/td&gt;
